SELECT s.id, s.movie_id, s.hall_id, s.start_time, s.end_time, s.price, s.status, h.name AS hall_name, m.title AS movie_title, m.poster AS movie_poster, m.duration AS movie_duration, c.id AS cinema_id, c.name AS cinema_name FROM schedule s INNER JOIN hall h ON s.hall_id = h.id INNER JOIN cinema c ON h.cinema_id = c.id LEFT JOIN movie m ON s.movie_id = m.id
AND c.status = 1 AND h.status = 1
AND s.movie_id = #{params.movieId}
AND c.id = #{params.cinemaId}
AND DATE(s.start_time) = #{params.date}
AND s.start_time >= #{params.startTime}
AND s.end_time <= #{params.endTime}
AND s.start_time > NOW()
AND s.start_time <= NOW() AND s.end_time > NOW()
AND s.end_time <= NOW()
ORDER BY s.start_time ASC
LIMIT #{params.offset}, #{params.pageSize}

SELECT COUNT(*)
FROM schedule s
INNER JOIN hall h ON s.hall_id = h.id
INNER JOIN cinema c ON h.cinema_id = c.id

    AND c.status = 1
    AND h.status = 1

